import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import Captcha from "../../components/Captcha";
import Layout from "../../components/layout/Layout";

const roles = [
  { value: "admin", label: "Admin" },
  { value: "instructor", label: "Instructor" },
  { value: "student", label: "Student" },
  { value: "content", label: "Content Creator" },
];

function Login() {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("");
  const [captchaInput, setCaptchaInput] = useState("");
  const [captchaCode, setCaptchaCode] = useState("");
  const [error, setError] = useState("");

  const handleLogin = () => {
    if (!email || !password || !role || !captchaInput) {
      setError("All fields are required");
      return;
    }
    if (captchaInput.toUpperCase() !== captchaCode) {
      setError("Captcha is incorrect");
      return;
    }
    setError("");

    localStorage.setItem("role", role);

    switch (role) {
      case "admin":
        navigate("/admin");
        break;
      case "instructor":
        navigate("/instructor");
        break;
      case "student":
        navigate("/student");
        break;
      case "content":
        navigate("/content");
        break;
      default:
        navigate("/");
    }
  };

  return (
    <Layout pageTitle="NexaLearn LMS | Login">
      <div
        style={{
          maxWidth: "400px",
          margin: "auto",
          paddingTop: "20px",
          paddingBottom: "40px",
        }}
      >
        {error && (
          <div
            style={{
              marginBottom: "15px",
              backgroundColor: "#fdecea",
              color: "#b71c1c",
              padding: "10px 15px",
              borderRadius: "4px",
              fontWeight: "600",
              fontSize: "0.9rem",
            }}
          >
            {error}
          </div>
        )}

        <input
          type="email"
          placeholder="Username or email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          style={{
            width: "100%",
            padding: "12px 15px",
            marginBottom: "15px",
            borderRadius: "4px",
            border: "1px solid #ccc",
            fontSize: "1rem",
          }}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          style={{
            width: "100%",
            padding: "12px 15px",
            marginBottom: "15px",
            borderRadius: "4px",
            border: "1px solid #ccc",
            fontSize: "1rem",
          }}
        />

        <select
          value={role}
          onChange={(e) => setRole(e.target.value)}
          style={{
            width: "100%",
            padding: "12px 15px",
            marginBottom: "15px",
            borderRadius: "4px",
            border: "1px solid #ccc",
            fontSize: "1rem",
            color: role ? "#000" : "#888",
          }}
        >
          <option value="" disabled>
            Select Role
          </option>
          {roles.map((r) => (
            <option key={r.value} value={r.value}>
              {r.label}
            </option>
          ))}
        </select>

        <Captcha onChange={setCaptchaCode} />

        <input
          type="text"
          placeholder="Enter verification code"
          value={captchaInput}
          onChange={(e) => setCaptchaInput(e.target.value)}
          style={{
            width: "100%",
            padding: "12px 15px",
            margin: "12px 0 25px",
            borderRadius: "4px",
            border: "1px solid #ccc",
            fontSize: "1rem",
          }}
        />

        <button
          onClick={handleLogin}
          style={{
            width: "100%",
            backgroundColor: "#a71010",
            color: "#fff",
            padding: "14px 0",
            fontWeight: "600",
            fontSize: "1.1rem",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
            transition: "background-color 0.3s ease",
          }}
          onMouseOver={(e) => (e.target.style.backgroundColor = "#800000")}
          onMouseOut={(e) => (e.target.style.backgroundColor = "#a71010")}
        >
          Log in
        </button>

        <div
          style={{
            marginTop: "18px",
            fontSize: "0.9rem",
            color: "#b34700",
            textAlign: "left",
            cursor: "pointer",
            userSelect: "none",
          }}
          onClick={() => alert("Lost password flow to be implemented")}
        >
          Lost password?
        </div>

        <div
          style={{
            marginTop: "10px",
            fontSize: "0.9rem",
            textAlign: "center",
          }}
        >
          Don't have an account?{" "}
          <Link to="/register" style={{ color: "#a71010" }}>
            Register
          </Link>
        </div>
      </div>
    </Layout>
  );
}

export default Login;
